-- 0020: 新增 TeamMatch 專案（OpenAI Build Week 社群黑客松），排在 aws-hackathon 之後
-- 冪等：teammatch 已存在時不再挪動其他專案的 sort_order，重跑只會覆蓋同一筆內容
UPDATE projects SET sort_order = sort_order + 1, updated_at = datetime('now')
WHERE sort_order > (SELECT sort_order FROM projects WHERE id = 'aws-hackathon')
  AND NOT EXISTS (SELECT 1 FROM projects WHERE id = 'teammatch');

INSERT OR REPLACE INTO projects (id, zh, en, sort_order, updated_at)
VALUES ('teammatch', '{"id":"teammatch","category":"大學校外作品","title":"TeamMatch — 黑客松找隊友平台","period":"2026","description":"OpenAI Build Week 社群黑客松，三人當天從零做完：報名活動後在同場報名者裡滑卡找隊友，雙方都按讚才成立配對、交換聯絡方式。我負責登入／個人檔案／導覽列，以及最後把三個人的分支合併收尾。開工前先凍結一份介面規格（collection 名稱、欄位、Document ID、API 簽名、路由），三人平行寫、合併時不必改到對方的檔案。（AI 輔助開發，Codex）","tags":["Next.js","TypeScript","Firebase Firestore","Tailwind CSS","介面契約"],"detail":{"purpose":"黑客松找隊友大多靠緣分：主辦的 Discord 洗版、認識誰就跟誰一組。TeamMatch 把這件事變成流程——先報名活動、標記自己缺隊友，然後只在同一場活動的報名者裡滑卡，雙方都按讚才交換聯絡方式。\n\n題目是三個人開場後現想的：Luma 的活動頁、獎金獵人的賞金、Tinder 的滑卡，把三個現成的東西接起來。","concept":"【開工前先凍結接口】一天的比賽最怕的不是寫不完，是合併時打架。所以先寫一份 SPEC：五個 Firestore collection 的名稱、欄位一律 camelCase、每個 Document ID 的組法、每支 API 的參數與回傳型別、每條路由的路徑。頁面怎麼寫、component 怎麼拆各自決定，但這六項凍結不動。三人各拿一塊（登入／個人檔案、活動列表與報名、滑卡與配對）平行寫。\n\n【重複操作用 Document ID 擋掉】報名的文件 ID 是 {eventId}__{userId}，同一人重複報名只會蓋回同一筆；滑卡是 {eventId}__{swiperId}__{targetId}；配對是 {eventId}__{userA}__{userB}，兩個 userId 先排序才組 ID——不排序的話「A 滑 B」和「B 滑 A」會生出兩筆配對。用命名規則換掉一整套去重查詢。\n\n【我這塊：登入刻意做成假的】不接 Firebase Auth，登入頁直接列出 profiles 裡的所有人，點一張卡就以那個身分進站，localStorage 存 userId。黑客松要的是評審和隊友兩分鐘內能互相配對給人看，不是密碼安全。這不是登入系統，是身分切換器，真要上線得整個換掉。\n\n個人檔案編輯直接讀寫 Firestore 文件：技能欄用逗號分隔字串轉陣列、下方即時顯示 pill；頭像不做上傳，用 DiceBear 依 avatarSeed 生成，省掉 Storage 和圖片處理。","outcome":"當天做出可跑的完整流程：建個人檔案 → 瀏覽／發布活動 → 報名（可標記「已有隊友」與隊伍名稱）→ 在該活動的候選人裡滑卡 → 互相按讚跳出配對成功 → 配對列表看到對方的 Email 和 Discord。活動人數上限以隊伍人數加總計算，不是報名筆數；已經有隊友的人不會進滑卡候選池。\n\n現場最花時間的是 Firestore 連不上：SDK 預設的 WebChannel 串流建不起來，改成 initializeFirestore(app, { experimentalForceLongPolling: true }) 強制走長輪詢才通。這行是我在把配對頁合併進主線時修的。\n\n沒有名次，也還沒部署上線。Firestore 安全規則和真正的登入都停在 demo 等級，要公開得先補這兩塊。","tech":[{"group":"介面契約","items":[{"name":"開工前凍結規格","desc":"collection 名稱、camelCase 欄位、Document ID 組法、API 簽名、路由路徑先定死寫成 SPEC.md；頁面實作各自自由，合併時不必改對方的檔案"},{"name":"複合 Document ID 去重","desc":"報名 {eventId}__{userId}、滑卡 {eventId}__{swiperId}__{targetId}、配對 {eventId}__{userA}__{userB}（兩個 ID 先排序）；重複操作變成覆蓋同一筆，不需額外的去重查詢或交易"}]},{"group":"登入與個人檔案（我負責）","items":[{"name":"Demo 身分切換","desc":"不接 Firebase Auth，列出 profiles 讓人選一張卡進站、localStorage 存 currentUserId；換到 demo 當下能立刻多人互相配對，代價是沒有真正的驗證"},{"name":"Firestore 直讀寫表單","desc":"getDoc / updateDoc 編輯個人檔案，技能逗號字串轉陣列並即時預覽；頭像用 DiceBear 依 avatarSeed 生成，免上傳與 Storage"},{"name":"導覽列狀態同步","desc":"依 pathname 高亮並重讀當前 profile；非同步載入用 cancelled 旗標，避免元件卸載後才 setState"}]},{"group":"整合與除錯","items":[{"name":"Firestore 強制長輪詢","desc":"預設 WebChannel 串流建不起來，改 initializeFirestore 帶 experimentalForceLongPolling 才能穩定讀寫"},{"name":"三分支合併收尾","desc":"把三人分支併回主線，補上聯絡欄位、活動人數上限（隊伍人數加總而非報名筆數）、已有隊友者不進滑卡池，並同步更新 SPEC"}]}],"github":"https://github.com/CHU-BO-YU/teamder"}}', '{"id":"teammatch","category":"大學校外作品","title":"TeamMatch — Hackathon Teammate Finder","period":"2026","description":"Built in a day by three people at an OpenAI Build Week community hackathon: register for an event, then swipe through the other registrants to find teammates — a match forms only when both sides like each other, and contact details are exchanged. I owned login, profile, and the navbar, and did the final merge of all three branches. We froze an interface spec before writing any code (collection names, field names, document IDs, API signatures, routes), so three people could work in parallel and merge without touching each other''s files. (AI-assisted development, Codex)","tags":["Next.js","TypeScript","Firebase Firestore","Tailwind CSS","Interface Contract"],"detail":{"purpose":"Finding hackathon teammates usually comes down to luck: a flooded Discord channel, or teaming up with whoever you already know. TeamMatch turns it into a flow — register for the event, flag that you still need teammates, then swipe only through people registered for that same event, and exchange contact details only after both sides like each other.\n\nThe three of us came up with the idea after the kickoff: Luma''s event pages, a bounty board''s prize listing, and Tinder''s swipe deck, wired together.","concept":"[Freeze the interfaces before writing code] In a one-day build, the risk isn''t running out of time — it''s the merge going wrong. So we wrote a SPEC first: five Firestore collection names, camelCase everywhere, how each document ID is composed, the arguments and return types of every API function, and every route path. Page structure and component breakdown were left to each person, but those six things were frozen. Each of us took one slice (login/profile, event list and registration, swipe and match) and worked in parallel.\n\n[Duplicate actions blocked by document ID] A registration''s document ID is {eventId}__{userId}, so registering twice just overwrites the same document; a swipe is {eventId}__{swiperId}__{targetId}; a match is {eventId}__{userA}__{userB}, with the two user IDs sorted before composing the ID — without sorting, \"A swipes B\" and \"B swipes A\" would produce two separate matches. A naming rule instead of a whole layer of dedup queries.\n\n[My slice: the login is deliberately fake] No Firebase Auth. The login page lists every profile in the database; click a card and you''re in as that person, with the user ID kept in localStorage. What a hackathon demo needs is judges and teammates matching with each other within two minutes, not password security. It isn''t a login system, it''s an identity switcher, and it would have to be replaced entirely to ship.\n\nProfile editing reads and writes the Firestore document directly: the skills field is a comma-separated string parsed into an array with pills previewed live below it, and avatars are generated by DiceBear from avatarSeed instead of uploaded, which cuts out Storage and image handling.","outcome":"The whole flow worked by the end of the day: create a profile → browse or publish events → register (optionally flagging \"already have a team\" plus a team name) → swipe through that event''s candidates → mutual likes pop a match → the matches page shows the other person''s email and Discord. Event capacity is computed by summing team sizes rather than counting registration documents, and people who already have a team never enter the swipe pool.\n\nThe biggest time sink on the day was Firestore refusing to connect: the SDK''s default WebChannel stream wouldn''t establish, and it only worked after switching to initializeFirestore(app, { experimentalForceLongPolling: true }). I made that fix while merging the matching pages into main.\n\nNo placing, and it isn''t deployed. The Firestore security rules and the login are both still at demo level — both would need real work before this could go public.","tech":[{"group":"Interface Contract","items":[{"name":"Spec frozen before coding","desc":"Collection names, camelCase fields, document ID composition, API signatures, and route paths were fixed in SPEC.md; page implementation stayed free, so merging never required editing someone else''s files"},{"name":"Composite document IDs for idempotency","desc":"Registration {eventId}__{userId}, swipe {eventId}__{swiperId}__{targetId}, match {eventId}__{userA}__{userB} with the IDs sorted first; a repeated action overwrites the same document, so no dedup queries or transactions are needed"}]},{"group":"Login & Profile (my slice)","items":[{"name":"Demo identity switcher","desc":"No Firebase Auth: the login page lists profiles, picking a card signs you in as that user, and currentUserId lives in localStorage — traded real authentication for several people being able to match each other on the spot"},{"name":"Forms writing straight to Firestore","desc":"getDoc / updateDoc for profile editing, comma-separated skills parsed into an array with a live pill preview, and DiceBear avatars derived from avatarSeed instead of uploads"},{"name":"Navbar state sync","desc":"Highlights by pathname and reloads the current profile on navigation; the async load uses a cancelled flag so it never calls setState after unmount"}]},{"group":"Integration & Debugging","items":[{"name":"Forced Firestore long polling","desc":"The default WebChannel stream wouldn''t establish; passing experimentalForceLongPolling to initializeFirestore was what made reads and writes stable"},{"name":"Merging three branches","desc":"Merged all three branches back into main and added the contact fields, event capacity (summed team sizes rather than registration count), and exclusion of already-teamed users from the swipe pool, updating the SPEC to match"}]}],"github":"https://github.com/CHU-BO-YU/teamder"}}',
  COALESCE((SELECT sort_order + 1 FROM projects WHERE id = 'aws-hackathon'), 4),
  datetime('now'));
